scenario:
J: AWS Config flagged this S3 bucket as non-compliant. Missing encryption, versioning, logging, and public access block. Fix it:
```hcl
resource "aws_s3_bucket" "data" {
  bucket = "company-data-bucket"
}
```

J: GuardDuty alert - EC2 instance exposed to internet. This security group is wide open. Fix it:
```hcl
resource "aws_security_group" "app" {
  name   = "app-sg"
  vpc_id = var.vpc_id

  ingress {
    from_port   = 0
    to_port     = 65535
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}
```

J: IAM Access Analyzer found this overprivileged policy. Wildcard actions on wildcard resources with trust to ANY AWS account. Fix it:
```hcl
resource "aws_iam_policy" "app_policy" {
  name = "app-policy"
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = ["s3:*"]
        Resource = ["*"]
      },
      {
        Effect   = "Allow"
        Action   = ["sts:AssumeRole"]
        Resource = ["*"]
      }
    ]
  })
}

resource "aws_iam_role" "app_role" {
  name = "app-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Effect    = "Allow"
      Principal = { AWS = "*" }
      Action    = "sts:AssumeRole"
    }]
  })
}
```

J: Terraform state file found in public S3 bucket. State contains secrets! Fix the backend configuration:
```hcl
terraform {
  backend "s3" {
    bucket = "company-terraform-state"
    key    = "prod/terraform.tfstate"
    region = "us-east-1"
  }
}
```
